import React, { useEffect, useState } from 'react';
import axios from '../api/axios';
import { useNavigate } from 'react-router-dom';

export default function UserDashboard() {
    const navigate = useNavigate();
    const [stats, setStats] = useState({ activeBookings: 0, totalLots: 0, recentBookings: [] });
    const [lots, setLots] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchDashboardData = async () => {
            try {
                // Fetch user's bookings
                const bookingsRes = await axios.get('/bookings/my');
                const active = bookingsRes.data.filter(b => b.status === 'Active' || b.status === 'Booked');

                // Fetch parking lots
                const lotsRes = await axios.get('/parking');

                setStats({
                    activeBookings: active.length,
                    totalLots: lotsRes.data.length,
                    recentBookings: bookingsRes.data.slice(0, 3) // Latest 3
                });

                setLots(lotsRes.data.slice(0, 3)); // Show 3 nearby lots
                setLoading(false);
            } catch (err) {
                console.error("Error loading dashboard data:", err);
                setLoading(false);
            }
        };

        fetchDashboardData();
    }, []);

    if (loading) {
        return <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100%', color: 'var(--text-muted)' }}>Loading dashboard...</div>;
    }

    return (
        <div style={{ animation: 'fadeIn 0.4s ease-out' }}>

            {/* QUICK STATS - Top Grid matching the two major blocks */}
            <div style={{ display: 'grid', gridTemplateColumns: 'minmax(300px, 1fr) minmax(350px, 1.5fr)', gap: '24px', marginBottom: '24px' }}>

                {/* Block 1: Real-time Stats */}
                <div style={{ background: 'white', borderRadius: 'var(--radius-lg)', padding: '30px', boxShadow: 'var(--shadow-sm)', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
                    <div style={{ paddingBottom: '20px', borderBottom: '1px solid #f1f5f9' }}>
                        <div style={{ fontSize: '0.9rem', color: 'var(--text-muted)', fontWeight: '600', marginBottom: '8px' }}>Active Reservations</div>
                        <div style={{ fontSize: '2.5rem', fontWeight: '800', color: 'var(--text-primary)' }}>{stats.activeBookings}</div>
                    </div>
                    <div style={{ paddingBottom: '20px', borderBottom: '1px solid #f1f5f9' }}>
                        <div style={{ fontSize: '0.9rem', color: 'var(--text-muted)', fontWeight: '600', marginBottom: '8px' }}>Available Locations</div>
                        <div style={{ fontSize: '2.5rem', fontWeight: '800', color: 'var(--text-primary)' }}>{stats.totalLots}</div>
                    </div>
                    <div style={{ gridColumn: '1 / -1', paddingTop: '10px' }}>
                        <button style={{ width: '100%', background: '#f8fafc', border: 'none', padding: '14px', borderRadius: '12px', fontWeight: '600', color: 'var(--text-secondary)', cursor: 'pointer', transition: 'background 0.2s' }} onClick={() => navigate('/parking')}>
                            + Book New Parking
                        </button>
                    </div>
                </div>

                {/* Block 2: Map to "Urgent Tasks" list */}
                <div style={{ background: 'white', borderRadius: 'var(--radius-lg)', padding: '30px', boxShadow: 'var(--shadow-sm)' }}>
                    <div style={{ fontSize: '1.2rem', fontWeight: '800', color: 'var(--text-primary)', marginBottom: '20px' }}>Recent Activity</div>
                    {stats.recentBookings.length === 0 ? (
                        <div style={{ textAlign: 'center', color: 'var(--text-muted)', padding: '20px 0' }}>No recent activity.</div>
                    ) : (
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                            {stats.recentBookings.map(b => (
                                <div key={b._id} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingBottom: '16px', borderBottom: '1px solid #f1f5f9' }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
                                        <div style={{ width: '12px', height: '12px', borderRadius: '50%', background: b.status === 'Active' ? 'var(--status-success)' : 'var(--text-muted)', border: '2px solid white', boxShadow: '0 0 0 1px #e2e8f0' }}></div>
                                        <span style={{ fontSize: '1rem', fontWeight: '500', color: 'var(--text-secondary)' }}>{b.vehicleNumber} ({b.slotId?.slotNumber || "Slot"})</span>
                                    </div>
                                    <div style={{ fontSize: '0.8rem', fontWeight: '700', padding: '4px 10px', borderRadius: '8px', background: b.status === 'Active' ? 'var(--tag-mint)' : 'var(--tag-lavender)', color: b.status === 'Active' ? '#065f46' : '#5b21b6' }}>
                                        • {b.status}
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div> {/* End Top Grid */}

            <div style={{ display: 'grid', gridTemplateColumns: '1.5fr 1fr', gap: '24px' }}>
                {/* NEARBY LOCATIONS (Matching "Project Directory") */}
                <div style={{ background: 'white', borderRadius: 'var(--radius-lg)', padding: '30px', boxShadow: 'var(--shadow-sm)' }}>
                     <h2 style={{ fontSize: '1.2rem', fontWeight: '800', color: 'var(--text-primary)', marginBottom: '24px' }}>Available Locations Directory</h2>
                     <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                        {lots.map(lot => (
                            <div key={lot._id} style={{ paddingBottom: '16px', borderBottom: '1px solid #f1f5f9', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }} onClick={() => navigate(`/slots/${lot._id}`)}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
                                    <div style={{ color: 'var(--text-muted)', fontSize: '1.2rem' }}><i className="fa-solid fa-location-dot"></i></div>
                                    <div>
                                        <div style={{ fontWeight: '700', color: 'var(--text-primary)', fontSize: '0.95rem' }}>{lot.name}</div>
                                        <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>{lot.location}</div>
                                    </div>
                                </div>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                                    {/* Mock Avatars mimicking reference Team layout */}
                                    <div style={{ display: 'flex', position: 'relative', width: '32px' }}>
                                        <div style={{ width: '28px', height: '28px', borderRadius: '50%', background: 'var(--tag-peach)', border: '2px solid white', position: 'absolute', right: 0 }}></div>
                                        <div style={{ width: '28px', height: '28px', borderRadius: '50%', background: 'var(--tag-mint)', border: '2px solid white', position: 'absolute', right: '12px' }}></div>
                                    </div>
                                </div>
                            </div>
                        ))}
                        <button onClick={() => navigate('/parking')} style={{ background: 'none', border: '1px solid #e2e8f0', color: 'var(--text-primary)', padding: '12px', borderRadius: '12px', fontWeight: '600', cursor: 'pointer', fontSize: '0.9rem', marginTop: '10px' }}>
                            + View All Locations
                        </button>
                     </div>
                </div>

                {/* NOTIFICATIONS/ALERTS (Matching "New Comments") */}
                <div style={{ background: 'white', borderRadius: 'var(--radius-lg)', padding: '30px', boxShadow: 'var(--shadow-sm)', alignSelf: 'start' }}>
                    <div style={{ fontSize: '1.2rem', fontWeight: '800', color: 'var(--text-primary)', marginBottom: '20px' }}>System Alerts</div>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                        <div style={{ padding: '16px', background: 'var(--bg-primary)', borderRadius: '14px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                            <div style={{ display: 'flex', gap: '12px', alignItems: 'center' }}>
                                <div style={{ width: '36px', height: '36px', borderRadius: '50%', background: 'linear-gradient(135deg, var(--accent-primary), var(--accent-secondary))', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><i className="fa-solid fa-robot"></i></div>
                                <div>
                                    <div style={{ fontSize: '0.9rem', color: 'var(--text-primary)', fontWeight: '600' }}>ParkSense AI initialized</div>
                                    <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>You can now ask the chatbot to find parking!</div>
                                </div>
                            </div>
                            <i className="fa-solid fa-chevron-right" style={{ color: 'var(--text-muted)', fontSize: '0.8rem' }}></i>
                        </div>
                    </div>

                    {/* Tags matching the grid tags natively */}
                    <div style={{ display: 'flex', gap: '12px', marginTop: '30px' }}>
                        <div style={{ flex: 1, padding: '12px', background: 'var(--tag-lavender)', borderRadius: '12px' }}>
                            <div style={{ fontSize: '0.75rem', color: '#6d28d9', fontWeight: '800' }}>#SmartNav</div>
                        </div>
                        <div style={{ flex: 1, padding: '12px', background: 'var(--tag-mint)', borderRadius: '12px' }}>
                            <div style={{ fontSize: '0.75rem', color: '#047857', fontWeight: '800' }}>#EcoRoute</div>
                        </div>
                        <div style={{ flex: 1, padding: '12px', background: 'var(--tag-peach)', borderRadius: '12px' }}>
                            <div style={{ fontSize: '0.75rem', color: '#b45309', fontWeight: '800' }}>#Security</div>
                        </div>
                    </div>
                </div>
            </div> {/* End Bottom Grid */}

        </div>
    );
}
